
"use client"

import { useState, useEffect, useRef, useMemo } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { 
  Zap, Radio, ShieldAlert, Palette, 
  Camera, CarFront, AlertTriangle, Loader2, Clock, MapPin, 
  Footprints, Navigation, CheckCircle2, TrendingUp, Info, Trophy,
  Play, Map as MapIcon, ChevronRight, Crown, Star
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection } from "firebase/firestore";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 animate-pulse rounded-3xl">
      <Loader2 className="w-6 h-6 animate-spin text-accent" />
    </div>
  )
});

const RadarMap = dynamic(() => import("@/components/radar/radar-map"), { 
  ssr: false,
  loading: () => null
});

function getDistance(lat1: number, lon1: number, lat2: number, lon2: number) {
  const R = 6371e3;
  const phi1 = (lat1 * Math.PI) / 180;
  const phi2 = (lat2 * Math.PI) / 180;
  const deltaPhi = ((lat2 - lat1) * Math.PI) / 180;
  const deltaLambda = ((lon2 - lon1) * Math.PI) / 180;
  const a = Math.sin(deltaPhi / 2) * Math.sin(deltaPhi / 2) + Math.cos(phi1) * Math.cos(phi2) * Math.sin(deltaLambda / 2) * Math.sin(deltaLambda / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const MOCK_ALERTS = [
  { id: 1, type: "Radar", lat: 42.6629, lng: 21.1655, location: "Prishtinë, Qendër" },
  { id: 2, type: "Polici", lat: 42.215, lng: 21.125, location: "Autostrada, Ferizaj" },
  { id: 3, type: "Kontrollë", lat: 42.231, lng: 20.735, location: "Tranzit, Prizren" },
];

type SpeedoTheme = 'm3_modern' | 'rs_performance' | 'amg_performance' | 'porsche' | 'default';
type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const { user } = useUser();
  const db = useFirestore();
  const [speed, setSpeed] = useState(0);
  const [isDriving, setIsDriving] = useState(false);
  const [isTestMode, setIsTestMode] = useState(false);
  const [peakSpeed, setPeakSpeed] = useState(0);
  const [hasGps, setHasGps] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [theme, setTheme] = useState<SpeedoTheme>('m3_modern');
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const [tripTime, setTripTime] = useState(0);
  const [tripDistance, setTripDistance] = useState(0);
  const [brakeCount, setBrakeCount] = useState(0);
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [routePoints, setRoutePoints] = useState<[number, number][]>([]);

  const { toast } = useToast();
  const [currentCoords, setCurrentCoords] = useState<{ lat: number; lng: number } | null>(null);
  const lastPos = useRef<{ lat: number; lng: number; timestamp: number } | null>(null);
  const wakeLockRef = useRef<any>(null);

  const profileRef = useMemoFirebase(() => {
    if (!user || !db) return null;
    return doc(db, "users", user.uid);
  }, [user, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Advanced Test Mode Simulator (City Drive & 1 Hour Visualization)
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isTestMode) {
      let simLat = 42.6629;
      let simLng = 21.1655;
      let angle = 0;
      
      interval = setInterval(() => {
        setSpeed(prev => {
          // Realistic speed fluctuation
          const randomFactor = Math.random() * 20 - 10;
          let next = prev + randomFactor;
          
          if (next > 280) next = 240; // Don't just stay at peak
          if (next < 30) next = 60; // Keep moving
          
          // Random brake event
          if (Math.random() > 0.95 && isDriving) {
            next = Math.max(0, next - 50);
            setBrakeCount(b => b + 1);
          }

          if (isDriving) {
            if (next > peakSpeed) setPeakSpeed(Math.round(next));
            
            // Fast forward simulation: 1 tick = 1 minute of real time
            setTripTime(t => t + 60);
            
            // Accumulate distance based on speed
            const mps = next / 3.6;
            const distanceInMinute = mps * 60;
            setTripDistance(d => d + distanceInMinute);

            // Generate a moving GPS path (City Circuit)
            angle += 0.15;
            const radius = 0.005 + (angle * 0.0001); // Expanding spiral
            simLat += Math.sin(angle) * 0.0008;
            simLng += Math.cos(angle) * 0.0008;
            
            setRoutePoints(prevPoints => [...prevPoints, [simLat, simLng]]);
            setCurrentCoords({ lat: simLat, lng: simLng });
          }
          
          return Math.round(next);
        });
      }, 100); // 10 ticks per simulated "run" (reaching 1 hour in ~6 seconds)
    }
    return () => clearInterval(interval);
  }, [isTestMode, isDriving, peakSpeed]);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isDriving && !isTestMode) {
      interval = setInterval(() => {
        setTripTime(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isDriving, isTestMode]);

  const formatTime = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    if (hours > 0) return `${hours}h ${mins}m`;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const avgSpeed = useMemo(() => {
    if (tripTime === 0) return 0;
    return Math.round((tripDistance / tripTime) * 3.6);
  }, [tripDistance, tripTime]);

  const recordStatus = useMemo(() => {
    const cityName = profile?.city || 'Qytetin';
    if (peakSpeed > 280) return { type: 'KOSOVA', label: 'Më i shpejti në Kosovë sot!', sub: 'REKORD KOMBËTAR' };
    if (peakSpeed > 220) return { type: 'CITY', label: `Më i shpejti në ${cityName}!`, sub: 'REKORD LOKAL' };
    return null;
  }, [peakSpeed, profile?.city]);

  const nearestAlert = useMemo(() => {
    if (!currentCoords) return null;
    const alertsWithDist = MOCK_ALERTS.map(alert => ({
      ...alert,
      distance: getDistance(currentCoords.lat, currentCoords.lng, alert.lat, alert.lng)
    }));
    const nearby = alertsWithDist.filter(a => a.distance < 2000);
    if (nearby.length === 0) return null;
    return nearby.sort((a, b) => a.distance - b.distance)[0];
  }, [currentCoords]);

  useEffect(() => {
    const requestWakeLock = async () => {
      try {
        if ('wakeLock' in navigator && (isDriving || speed > 10)) {
          wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        }
      } catch (err: any) {}
    };
    const releaseWakeLock = async () => {
      if (wakeLockRef.current !== null) {
        try {
          await wakeLockRef.current.release();
          wakeLockRef.current = null;
        } catch (e) {}
      }
    };
    if (isDriving || speed > 10) requestWakeLock();
    else releaseWakeLock();
    return () => { releaseWakeLock(); };
  }, [isDriving, speed]);

  useEffect(() => {
    let watchId: number;
    if (mounted && !isTestMode) {
      if (!navigator.geolocation) return;
      watchId = navigator.geolocation.watchPosition(
        (position) => {
          setHasGps(true);
          const { latitude, longitude } = position.coords;
          const timestamp = position.timestamp;
          setCurrentCoords({ lat: latitude, lng: longitude });
          
          let currentKmh = 0;
          const directMps = position.coords.speed;

          if (directMps !== null && directMps !== undefined && directMps >= 0) {
            currentKmh = Math.round(directMps * 3.6);
          } else if (lastPos.current) {
            const distance = getDistance(lastPos.current.lat, lastPos.current.lng, latitude, longitude);
            const timeDiff = (timestamp - lastPos.current.timestamp) / 1000;
            if (timeDiff > 0 && distance > 0.1) {
              currentKmh = Math.round((distance / timeDiff) * 3.6);
            }
          }

          if (currentKmh > 420) return;

          setSpeed(prev => {
            if (isDriving && prev - currentKmh > 20 && currentKmh < prev) {
              setBrakeCount(b => b + 1);
            }
            return currentKmh;
          });

          if (isDriving) {
            setRoutePoints(prev => [...prev, [latitude, longitude]]);
            if (currentKmh > peakSpeed) setPeakSpeed(currentKmh);
            if (lastPos.current) {
              const d = getDistance(lastPos.current.lat, lastPos.current.lng, latitude, longitude);
              setTripDistance(prev => prev + d);
            }
          }

          lastPos.current = { lat: latitude, lng: longitude, timestamp };
        },
        (error) => {
          setHasGps(false);
          console.warn("GPS Status:", error.message);
        },
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    } else if (isTestMode) {
      setHasGps(true);
    } else {
      setSpeed(0);
      setHasGps(false);
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [isDriving, peakSpeed, mounted, isTestMode]);

  const getDetailedLocation = async (lat: number, lng: number) => {
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`);
      const data = await response.json();
      const address = data.address;
      const road = address.road || address.pedestrian || address.street || "";
      const suburb = address.suburb || address.neighbourhood || address.village || "";
      const city = address.city || address.town || profile?.city || "Kosovë";
      
      if (road && suburb) return `${road}, ${suburb}`;
      if (road) return road;
      if (suburb) return suburb;
      return city;
    } catch (e) {
      return profile?.city || "Kosovë";
    }
  };

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords) {
      toast({ variant: "destructive", title: "Gabim", description: "GPS duhet të jetë aktiv." });
      return;
    }
    setIsReporting(type);
    
    const detailedLocation = await getDetailedLocation(currentCoords.lat, currentCoords.lng);
    
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: detailedLocation,
      city: profile?.city || "Kosovo",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });

    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "Raportimi u krye!", description: `${type} në ${detailedLocation}.` });
    }, 1000);
  };

  const cycleTheme = () => {
    const themes: SpeedoTheme[] = ['m3_modern', 'rs_performance', 'amg_performance', 'porsche', 'default'];
    const currentIndex = themes.indexOf(theme);
    const nextIndex = (currentIndex + 1) % themes.length;
    setTheme(themes[nextIndex]);
  };

  const handleSaveRun = () => {
    if (!user || !db || !profile) return;
    setIsSaving(true);

    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Prishtinë",
      runType: "Top Speed",
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);

    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({
      title: "Gara u ruajt!",
      description: "Të dhënat u sinkronizuan me Rankingun.",
    });
    
    setIsSaving(false);
    setShowSummary(false);
  };

  if (!mounted) return <div className="min-h-screen bg-background" />;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden safe-bottom no-scrollbar relative">
      <div className="absolute inset-0 bg-gradient-to-b from-accent/5 via-transparent to-transparent pointer-events-none" />
      
      {/* Header Area */}
      <div className="p-6 flex items-center justify-between z-20 shrink-0">
        <div className="flex flex-col">
          <div className="flex items-center gap-2">
            {hasGps || isTestMode ? (
              <div className="w-2 h-2 rounded-full bg-accent animate-pulse shadow-[0_0_8px_#4de0f4]" />
            ) : (
              <div className="w-2 h-2 rounded-full bg-destructive" />
            )}
            <span className={cn(
              "text-[11px] font-black tracking-[0.2em] uppercase",
              (hasGps || isTestMode) ? "text-accent neon-text" : "text-muted-foreground"
            )}>
              {isTestMode ? "SIMULIMI" : hasGps ? "SIGNAL OK" : "NO SIGNAL"}
            </span>
          </div>
          <p className="text-[10px] text-muted-foreground font-bold mt-0.5 uppercase tracking-widest">DRIVE-RANK KOSOVO</p>
        </div>
        
        <div className="flex items-center gap-2.5">
          <Button 
            variant="outline" 
            size="icon" 
            onClick={() => { 
              setIsTestMode(!isTestMode); 
              if(!isTestMode) { 
                setPeakSpeed(0); 
                setRoutePoints([]); 
                setTripTime(0);
                setTripDistance(0);
              } 
            }} 
            className={cn("w-11 h-11 rounded-2xl glass border-white/5", isTestMode && "bg-accent/10 border-accent/30")}
          >
            <Zap className={cn("w-5 h-5", isTestMode ? "text-accent fill-accent/20" : "text-muted-foreground")} />
          </Button>
          <Button variant="outline" size="icon" onClick={cycleTheme} className="w-11 h-11 rounded-2xl glass border-white/5">
            <Palette className="w-5 h-5 text-accent" />
          </Button>
        </div>
      </div>

      {/* Quick Alerts */}
      <div className="px-6 mb-6 z-20 shrink-0">
        <div className="grid grid-cols-3 gap-3 p-1.5 rounded-3xl glass-card">
          <Button onClick={() => handleQuickReport('Radar')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl bg-red-600/10 hover:bg-red-600/20 border border-red-500/20 text-white transition-all active:scale-95">
            {isReporting === 'Radar' ? <Loader2 className="w-4 h-4 animate-spin text-red-500" /> : <Camera className="w-4 h-4 text-red-500" />}
            <span className="text-[9px] font-black italic tracking-widest uppercase">RADAR</span>
          </Button>
          <Button onClick={() => handleQuickReport('Polici')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl bg-blue-600/10 hover:bg-blue-600/20 border border-blue-500/20 text-white transition-all active:scale-95">
            {isReporting === 'Polici' ? <Loader2 className="w-4 h-4 animate-spin text-blue-500" /> : <ShieldAlert className="w-4 h-4 text-blue-500" />}
            <span className="text-[9px] font-black italic tracking-widest uppercase">POLICI</span>
          </Button>
          <Button onClick={() => handleQuickReport('Kontrollë')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl bg-zinc-800/30 hover:bg-zinc-800/50 border border-zinc-500/20 text-white transition-all active:scale-95">
            {isReporting === 'Kontrollë' ? <Loader2 className="w-4 h-4 animate-spin text-zinc-400" /> : <CarFront className="w-4 h-4 text-zinc-400" />}
            <span className="text-[9px] font-black italic tracking-widest uppercase">CHECK</span>
          </Button>
        </div>
      </div>

      {/* Main Speedometer Container */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-2 overflow-visible">
        <div className="relative w-full aspect-square flex items-center justify-center max-w-[340px] animate-float">
          {/* Theme Implementations */}
          {theme === 'm3_modern' && (
            <div className="w-full h-full relative flex items-center justify-center overflow-hidden rounded-[3.5rem] border border-white/5 shadow-2xl glass shadow-accent/5">
              <div className="absolute inset-0 z-0 opacity-40">
                <RadarMap center={currentCoords ? [currentCoords.lat, currentCoords.lng] : [42.6629, 21.1655]} alerts={[]} />
              </div>
              <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-black/70 z-[5]" />
              
              <div className="absolute inset-0 z-10 flex items-center justify-between px-8">
                <div className="flex flex-col gap-1.5 items-end">
                  {[...Array(16)].map((_, i) => (
                    <div key={i} className={cn("w-14 h-1 rounded-full skew-x-[-30deg] transition-all duration-300", (16 - i) * 18 <= speed ? "bg-blue-500 shadow-[0_0_15px_#3b82f6]" : "bg-white/5")} />
                  ))}
                </div>
                <div className="flex flex-col gap-1.5 items-start">
                  {[...Array(16)].map((_, i) => (
                    <div key={i} className={cn("w-14 h-1 rounded-full skew-x-[30deg] transition-all duration-300", (16 - i) * 18 <= speed ? (16 - i > 13 ? "bg-red-600 shadow-[0_0_20px_red]" : "bg-blue-600") : "bg-white/5")} />
                  ))}
                </div>
              </div>
              
              <div className="flex flex-col items-center justify-center text-center z-20 w-full">
                <div className="flex items-center justify-center gap-1.5 mb-3">
                   <div className="w-2 h-4 bg-blue-700 rounded-sm" />
                   <div className="w-2 h-4 bg-blue-400 rounded-sm" />
                   <div className="w-2 h-4 bg-red-600 rounded-sm" />
                </div>
                <div className="relative">
                  <span className="text-[10rem] font-black italic tracking-tighter text-white leading-none tabular-nums drop-shadow-[0_0_40px_rgba(255,255,255,0.15)]">
                    {speed}
                  </span>
                  <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-20 h-1 bg-accent/20 rounded-full blur-sm" />
                </div>
                <span className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.5em] mt-6 italic">M PERFORMANCE</span>
                <div className="mt-6 flex gap-3">
                   <Badge className="bg-blue-600/20 text-blue-400 border-blue-500/30 text-[10px] font-black px-4">SPORT+</Badge>
                   <Badge className="bg-red-600/20 text-red-500 border-red-500/30 text-[10px] font-black italic px-4">M</Badge>
                </div>
              </div>
            </div>
          )}

          {theme === 'rs_performance' && (
            <div className="w-full h-full relative flex items-center justify-center bg-[#050505] rounded-[4rem] border border-white/10 overflow-hidden shadow-[inset_0_0_50px_rgba(255,0,0,0.05)]">
              <div className="absolute top-10 left-12 right-12 h-2 flex gap-1.5">
                {[...Array(30)].map((_, i) => (
                  <div key={i} className={cn("flex-1 h-full transition-all duration-150 rounded-sm", (i / 30) * 340 <= speed ? (i > 24 ? "bg-red-600 shadow-[0_0_20px_red]" : "bg-white shadow-[0_0_10px_white]") : "bg-white/5")} />
                ))}
              </div>
              <div className="flex flex-col items-center">
                <span className="text-sm font-black text-red-600 tracking-[0.8em] mb-4">RS</span>
                <span className="text-[9rem] font-black text-white leading-none tracking-tighter tabular-nums">{speed}</span>
                <div className="flex flex-col items-center gap-2 mt-8">
                  <span className="text-[10px] font-black text-zinc-500 tracking-[0.6em] uppercase">QUATTRO</span>
                  <div className="h-1 w-16 bg-red-600 rounded-full shadow-[0_0_10px_red]" />
                </div>
              </div>
            </div>
          )}

          {theme === 'amg_performance' && (
            <div className="w-full h-full relative flex items-center justify-center bg-black rounded-[4rem] border border-zinc-800/50 overflow-hidden shadow-2xl">
               <svg className="absolute inset-0 w-full h-full p-6" viewBox="0 0 100 100">
                <circle cx="50" cy="50" r="46" fill="none" stroke="rgba(255,255,255,0.03)" strokeWidth="3" strokeDasharray="240 360" strokeLinecap="round" transform="rotate(120 50 50)" />
                <circle cx="50" cy="50" r="46" fill="none" stroke={speed > 280 ? "#ef4444" : "#eab308"} strokeWidth="4" strokeDasharray={`${(speed / 360) * 240} 360`} strokeLinecap="round" transform="rotate(120 50 50)" className="transition-all duration-300 shadow-[0_0_25px_rgba(234,179,8,0.4)]" />
              </svg>
              <div className="flex flex-col items-center z-10">
                <span className="text-[14px] font-black text-zinc-500 tracking-[0.8em] mb-6 italic opacity-50">AMG</span>
                <span className="text-[10rem] font-black text-white leading-none tracking-tighter tabular-nums drop-shadow-[0_15px_30px_rgba(0,0,0,1)]">{speed}</span>
                <div className="mt-8 flex items-center gap-4">
                   <div className="px-5 py-1 bg-yellow-500 text-black text-[11px] font-black italic rounded-sm shadow-lg shadow-yellow-500/20">RACE</div>
                   <span className="text-sm font-black text-yellow-500 tracking-widest">S+</span>
                </div>
              </div>
            </div>
          )}

          {theme === 'porsche' && (
            <div className="w-full h-full relative flex items-center justify-center bg-zinc-950 rounded-full border-[12px] border-zinc-900 shadow-[0_40px_80px_rgba(0,0,0,0.6),inset_0_0_60px_rgba(255,255,255,0.02)]">
              {[...Array(41)].map((_, i) => {
                const angle = -140 + (i * 7);
                return (
                  <div key={i} className={cn("absolute w-0.5 h-5 bg-zinc-800 origin-bottom bottom-1/2 left-1/2 -translate-x-1/2", i % 5 === 0 && "h-8 w-1 bg-zinc-400")} style={{ transform: `translateX(-50%) rotate(${angle}deg) translateY(-145px)` }} />
                )
              })}
              <div className="absolute w-2 h-[160px] bg-red-600 origin-bottom bottom-1/2 left-1/2 -translate-x-1/2 transition-transform duration-300 ease-out z-20 rounded-full shadow-[0_0_20px_red]" style={{ transform: `translateX(-50%) rotate(${-140 + (Math.min(speed, 350) / 350) * 280}deg)` }} />
              <div className="absolute bottom-1/2 left-1/2 -translate-x-1/2 translate-y-1/2 w-8 h-8 bg-black rounded-full z-30 border-2 border-zinc-800" />
              <div className="flex flex-col items-center z-10 translate-y-24 glass px-10 py-4 rounded-[2rem] border border-white/5 shadow-2xl">
                <span className="text-6xl font-black text-white leading-none tracking-tight tabular-nums">{speed}</span>
                <span className="text-[9px] font-black text-red-600 uppercase tracking-[0.6em] mt-2 italic">GT3 RS</span>
              </div>
            </div>
          )}

          {theme === 'default' && (
            <div className="relative w-72 h-72 flex items-center justify-center">
              <div className="absolute inset-0 rounded-full border-[12px] border-white/5 border-t-accent border-r-accent/40 transition-transform duration-300 shadow-[inset_0_0_30px_rgba(77,224,244,0.1)]" style={{ transform: `rotate(${135 + (Math.min(speed, 300) / 300) * 270}deg)` }} />
              <div className="flex flex-col items-center z-10">
                <span className="text-[8rem] font-black italic tracking-tighter neon-text tabular-nums leading-none">{speed}</span>
                <span className="text-xs font-black tracking-[0.4em] text-muted-foreground uppercase mt-4">KM/H</span>
              </div>
            </div>
          )}
        </div>

        {/* Action Controls */}
        <div className="w-full mt-10">
          <Button 
            onClick={() => { 
              if (isDriving || isTestMode) { 
                setShowSummary(true); 
                setIsDriving(false); 
                setIsTestMode(false); 
              } else { 
                setTripTime(0); 
                setTripDistance(0); 
                setBrakeCount(0); 
                setPeakSpeed(0); 
                setRoutePoints([]);
                setStartTime(new Date()); 
                setIsDriving(true); 
              } 
            }} 
            className={cn(
              "w-full h-20 rounded-[2.5rem] font-black text-xl uppercase italic tracking-tighter transition-all duration-500 shadow-2xl relative overflow-hidden group active:scale-[0.98]", 
              (isDriving || isTestMode) 
                ? "bg-red-600 hover:bg-red-700 text-white border-b-4 border-red-800" 
                : "bg-accent hover:bg-accent/90 text-background border-b-4 border-accent/70"
            )}
          >
            {(isDriving || isTestMode) ? (
              <div className="flex items-center gap-3">
                <div className="w-3 h-3 bg-white rounded-sm animate-pulse" />
                <span>NDALO MATJEN</span>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Play className="w-6 h-6 fill-background" />
                <span>FILLO MATJEN</span>
              </div>
            )}
            <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
          </Button>
        </div>

        {/* Real-time Stats Grid */}
        <div className="grid grid-cols-2 gap-4 w-full mt-8">
          {[
            { icon: Clock, label: "KOHA", value: formatTime(tripTime), color: "text-accent" },
            { icon: Navigation, label: "DISTANCA", value: `${(tripDistance / 1000).toFixed(2)} km`, color: "text-accent" },
            { icon: Footprints, label: "FRENIME", value: brakeCount, color: "text-red-500" },
            { icon: Zap, label: "PEAK", value: `${peakSpeed} km/h`, color: "text-yellow-500" }
          ].map((stat, i) => (
            <Card key={i} className="glass-card p-5 flex flex-col items-center justify-center gap-2.5 rounded-[2rem] border-white/[0.05]">
              <div className="flex items-center gap-2 opacity-50">
                <stat.icon className={cn("w-3.5 h-3.5", stat.color)} />
                <span className="text-[9px] font-black uppercase tracking-[0.2em]">{stat.label}</span>
              </div>
              <span className="text-2xl font-black italic tracking-tight">{stat.value}</span>
            </Card>
          ))}
        </div>

        {/* Intelligent Alerts Panel */}
        <div className="w-full mt-4">
          {nearestAlert ? (
            <div className="glass-card rounded-[2rem] p-5 border-red-500/20 bg-red-500/[0.03] animate-pulse shadow-red-500/5">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-2xl bg-red-500/10 flex items-center justify-center">
                  <AlertTriangle className="text-red-500 w-7 h-7" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">KUJDES: {nearestAlert.type.toUpperCase()} AFËR</p>
                  <p className="text-sm font-black truncate text-white">{nearestAlert.location}</p>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="h-1 flex-1 bg-red-500/10 rounded-full overflow-hidden">
                      <div className="h-full bg-red-500" style={{ width: `${Math.max(0, 100 - (nearestAlert.distance / 20))}%` }} />
                    </div>
                    <span className="text-[10px] font-black text-red-400">{Math.round(nearestAlert.distance)}m</span>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="glass-card rounded-[2.25rem] p-5 border-accent/10 flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-accent/5 flex items-center justify-center">
                <Radio className="text-accent w-7 h-7 animate-pulse" />
              </div>
              <div className="flex-1">
                <p className="text-[10px] font-black text-accent uppercase tracking-widest">RRUGËT E KOSOVËS</p>
                <p className="text-sm font-black text-white italic">Nuk u detektua asnjë radar afër.</p>
                <p className="text-[9px] font-bold text-muted-foreground uppercase mt-0.5 tracking-widest">KOMUNITETI LIVE</p>
              </div>
              <ChevronRight className="w-5 h-5 text-zinc-700" />
            </div>
          )}
        </div>
      </div>

      {/* Summary Dialog - Enhanced UX */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="glass border-white/5 sm:max-w-md max-h-[92vh] overflow-y-auto no-scrollbar rounded-[3rem] p-0 shadow-2xl">
          <div className="p-8 space-y-8">
            <DialogHeader className="flex flex-col items-center gap-3">
              <div className="w-20 h-20 bg-accent/10 rounded-[2rem] flex items-center justify-center pulse-ring shadow-accent/5">
                <CheckCircle2 className="w-10 h-10 text-accent" />
              </div>
              <DialogTitle className="text-3xl font-black italic uppercase tracking-tighter text-center">PERFORMANCA</DialogTitle>
            </DialogHeader>

            {/* Special Champion Card for Records */}
            {recordStatus && (
              <div className={cn(
                "relative overflow-hidden p-6 rounded-[2.5rem] border-2 shadow-2xl animate-in zoom-in-95 duration-500",
                recordStatus.type === 'KOSOVA' 
                  ? "bg-gradient-to-br from-yellow-500 to-amber-700 border-yellow-400/50 text-black shadow-yellow-500/20" 
                  : "bg-gradient-to-br from-blue-600 to-indigo-900 border-blue-400/50 text-white shadow-blue-500/20"
              )}>
                <div className="absolute -top-6 -right-6 opacity-20">
                  <Crown className="w-32 h-32" />
                </div>
                <div className="relative z-10 flex flex-col items-center text-center gap-2">
                  <div className="flex items-center gap-2 bg-black/10 px-3 py-1 rounded-full backdrop-blur-md">
                    <Star className="w-3 h-3 fill-current" />
                    <span className="text-[9px] font-black uppercase tracking-[0.2em]">{recordStatus.sub}</span>
                  </div>
                  <h3 className="text-2xl font-black italic uppercase tracking-tighter leading-tight">
                    {recordStatus.label}
                  </h3>
                  <div className="mt-2 text-[10px] font-bold uppercase tracking-widest opacity-80">
                    Sapo vendosët një rekord të ri me {peakSpeed} km/h
                  </div>
                </div>
                <div className="absolute inset-x-0 bottom-0 h-1 bg-gradient-to-r from-transparent via-white/40 to-transparent" />
              </div>
            )}

            <div className="space-y-6">
              <div className="h-56 w-full glass rounded-[2.5rem] border-white/5 overflow-hidden relative shadow-inner">
                <RouteMap points={routePoints} />
                <div className="absolute top-4 left-4 z-10">
                  <Badge className="bg-black/70 text-accent border-accent/20 text-[9px] font-black italic flex items-center gap-2 backdrop-blur-xl px-4 py-1.5 rounded-xl">
                    <MapIcon className="w-3 h-3" />
                    TELEMETRIA E GARËS
                  </Badge>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                {[
                  { label: "KOHA TOTAL", val: formatTime(tripTime) },
                  { label: "DISTANCA", val: `${(tripDistance / 1000).toFixed(2)} km` },
                  { label: "TOP SPEED", val: `${peakSpeed} km/h`, accent: true },
                  { label: "MESATARE", val: `${avgSpeed} km/h`, accent: true }
                ].map((stat, i) => (
                  <Card key={i} className="bg-white/[0.02] border-white/5 p-5 flex flex-col items-center rounded-[2rem]">
                    <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">{stat.label}</span>
                    <span className={cn("text-xl font-black italic", stat.accent && "text-accent")}>{stat.val}</span>
                  </Card>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <Card className="p-6 glass border-accent/10 rounded-[2.5rem] relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-accent/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl" />
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 rounded-xl bg-accent/10 flex items-center justify-center">
                    <TrendingUp className="w-5 h-5 text-accent" />
                  </div>
                  <span className="text-[11px] font-black uppercase text-accent tracking-widest">ANALIZA E DINAMIKËS</span>
                </div>
                <div className="flex justify-between items-end relative z-10">
                  <div className="space-y-1">
                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">FRENIME TOTALE</p>
                    <p className="text-3xl font-black italic">{brakeCount}</p>
                  </div>
                  <div className="text-right space-y-2">
                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">INTENSITETI</p>
                    <Badge className={cn(
                      "font-black italic text-[10px] px-6 py-1.5 rounded-full shadow-lg",
                      brakeCount > 5 ? "bg-red-500 shadow-red-500/10" : "bg-green-500 shadow-green-500/10"
                    )}>
                      {brakeCount > 5 ? "AGRESIVE" : "E PASTRË"}
                    </Badge>
                  </div>
                </div>
              </Card>

              <div className="p-6 bg-white/[0.03] border border-white/10 rounded-[2.5rem] space-y-3 relative">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-zinc-800/50 flex items-center justify-center">
                    <Info className="w-5 h-5 text-accent" />
                  </div>
                  <span className="text-[11px] font-black uppercase text-muted-foreground tracking-widest">DRIVE-RANK TIPS</span>
                </div>
                <p className="text-[13px] font-medium leading-relaxed text-zinc-300 italic">
                  {brakeCount > 5 
                    ? "Gomat dhe diskat po nxehen! Provo të frenosh më butë dhe më herët për një kthesë më të shpejtë dhe më shumë kontroll." 
                    : "Përformancë elitare! Vazhdo me këtë konsistencë për të ruajtur makinën dhe për të fituar pikë në Rankingun e pastërtisë."}
                </p>
              </div>
            </div>

            <div className="flex flex-col gap-3 pt-4">
              <Button onClick={handleSaveRun} disabled={isSaving} className="w-full h-16 bg-accent hover:bg-accent/90 text-background rounded-[2rem] font-black italic uppercase text-base shadow-2xl neon-glow">
                {isSaving ? <Loader2 className="w-6 h-6 animate-spin" /> : "RUAJ REKORDIN"}
              </Button>
              <Button variant="ghost" className="w-full h-14 rounded-[2rem] font-black italic uppercase text-sm text-zinc-500" onClick={() => setShowSummary(false)}>
                ANULO
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}
